import React, { useEffect, useState } from 'react';
import { getNearby, bookSession } from '../api';

export default function Counselors(){
  const [list, setList] = useState([]);
  useEffect(()=>{ navigator.geolocation.getCurrentPosition(async pos=>{ const l = await getNearby(pos.coords.latitude, pos.coords.longitude); setList(l); }, async ()=>{ const l = await getNearby(); setList(l); }); },[]);
  const book = async (id)=>{ const dt = new Date(); dt.setDate(dt.getDate()+1); const r = await bookSession(id, dt.toISOString()); alert('Booked: ' + JSON.stringify(r)); };
  return (
    <div style={{padding:20}}>
      <h2>Nearby Counselors</h2>
      <ul>
        {list.map(c=>(<li key={c.id}>
          <strong>{c.name}</strong> — {c.dept} — {c.distance_km} km
          <button style={{marginLeft:8}} onClick={()=>book(c.id)}>Book Next Day</button>
        </li>))}
      </ul>
    </div>
  );
}
